class User extends DataClass implements Insertable<User> {
  /// Primary key
  final int id;

  /// Unique identifier for external references
  final String uuid;

  /// Username for login
  final String username;

  /// Password hash (SHA-256)
  final String passwordHash;

  /// Password salt
  final String passwordSalt;

  /// User's full name
  final String fullName;

  /// Email address
  final String? email;

  /// Phone number
  final String? phone;

  /// User role (admin, principal, teacher, accountant)
  final String role;

  /// Profile photo as binary data
  final Uint8List? photo;

  /// Is user account active
  final bool isActive;

  /// Is this the system administrator (cannot be deleted)
  final bool isSystemAdmin;

  /// Comma-separated list of permissions (e.g. "view_fees,manage_students")
  final String? permissions;

  /// Last login timestamp
  final DateTime? lastLogin;

  /// Record creation timestamp
  final DateTime createdAt;

  /// Record update timestamp
  final DateTime updatedAt;
  const User(
      {required this.id,
      required this.uuid,
      required this.username,
      required this.passwordHash,
      required this.passwordSalt,
      required this.fullName,
      this.email,
      this.phone,
      required this.role,
      this.photo,
      required this.isActive,
      required this.isSystemAdmin,
      this.permissions,
      this.lastLogin,
      required this.createdAt,
      required this.updatedAt});
  @override
  Map<String, Expression> toColumns(bool nullToAbsent) {
    final map = <String, Expression>{};
    map['id'] = Variable<int>(id);
    map['uuid'] = Variable<String>(uuid);
    map['username'] = Variable<String>(username);
    map['password_hash'] = Variable<String>(passwordHash);
    map['password_salt'] = Variable<String>(passwordSalt);
    map['full_name'] = Variable<String>(fullName);
    if (!nullToAbsent || email != null) {
      map['email'] = Variable<String>(email);
    }
    if (!nullToAbsent || phone != null) {
      map['phone'] = Variable<String>(phone);
    }
    map['role'] = Variable<String>(role);
    if (!nullToAbsent || photo != null) {
      map['photo'] = Variable<Uint8List>(photo);
    }
    map['is_active'] = Variable<bool>(isActive);
    map['is_system_admin'] = Variable<bool>(isSystemAdmin);
    if (!nullToAbsent || permissions != null) {
      map['permissions'] = Variable<String>(permissions);
    }
    if (!nullToAbsent || lastLogin != null) {
      map['last_login'] = Variable<DateTime>(lastLogin);
    }
    map['created_at'] = Variable<DateTime>(createdAt);
    map['updated_at'] = Variable<DateTime>(updatedAt);
    return map;
  }

  UsersCompanion toCompanion(bool nullToAbsent) {
    return UsersCompanion(
      id: Value(id),
      uuid: Value(uuid),
      username: Value(username),
      passwordHash: Value(passwordHash),
      passwordSalt: Value(passwordSalt),
      fullName: Value(fullName),
      email:
          email == null && nullToAbsent ? const Value.absent() : Value(email),
      phone:
          phone == null && nullToAbsent ? const Value.absent() : Value(phone),
      role: Value(role),
      photo:
          photo == null && nullToAbsent ? const Value.absent() : Value(photo),
      isActive: Value(isActive),
      isSystemAdmin: Value(isSystemAdmin),
      permissions: permissions == null && nullToAbsent
          ? const Value.absent()
          : Value(permissions),
      lastLogin: lastLogin == null && nullToAbsent
          ? const Value.absent()
          : Value(lastLogin),
      createdAt: Value(createdAt),
      updatedAt: Value(updatedAt),
    );
  }

  factory User.fromJson(Map<String, dynamic> json,
      {ValueSerializer? serializer}) {
    serializer ??= driftRuntimeOptions.defaultSerializer;
    return User(
      id: serializer.fromJson<int>(json['id']),
      uuid: serializer.fromJson<String>(json['uuid']),
      username: serializer.fromJson<String>(json['username']),
      passwordHash: serializer.fromJson<String>(json['passwordHash']),
      passwordSalt: serializer.fromJson<String>(json['passwordSalt']),
      fullName: serializer.fromJson<String>(json['fullName']),
      email: serializer.fromJson<String?>(json['email']),
      phone: serializer.fromJson<String?>(json['phone']),
      role: serializer.fromJson<String>(json['role']),
      photo: serializer.fromJson<Uint8List?>(json['photo']),
      isActive: serializer.fromJson<bool>(json['isActive']),
      isSystemAdmin: serializer.fromJson<bool>(json['isSystemAdmin']),
      permissions: serializer.fromJson<String?>(json['permissions']),
      lastLogin: serializer.fromJson<DateTime?>(json['lastLogin']),
      createdAt: serializer.fromJson<DateTime>(json['createdAt']),
      updatedAt: serializer.fromJson<DateTime>(json['updatedAt']),
    );
  }
  @override
  Map<String, dynamic> toJson({ValueSerializer? serializer}) {
    serializer ??= driftRuntimeOptions.defaultSerializer;
    return <String, dynamic>{
      'id': serializer.toJson<int>(id),
      'uuid': serializer.toJson<String>(uuid),
      'username': serializer.toJson<String>(username),
      'passwordHash': serializer.toJson<String>(passwordHash),
      'passwordSalt': serializer.toJson<String>(passwordSalt),
      'fullName': serializer.toJson<String>(fullName),
      'email': serializer.toJson<String?>(email),
      'phone': serializer.toJson<String?>(phone),
      'role': serializer.toJson<String>(role),
      'photo': serializer.toJson<Uint8List?>(photo),
      'isActive': serializer.toJson<bool>(isActive),
      'isSystemAdmin': serializer.toJson<bool>(isSystemAdmin),
      'permissions': serializer.toJson<String?>(permissions),
      'lastLogin': serializer.toJson<DateTime?>(lastLogin),
      'createdAt': serializer.toJson<DateTime>(createdAt),
      'updatedAt': serializer.toJson<DateTime>(updatedAt),
    };
  }

  User copyWith(
          {int? id,
          String? uuid,
          String? username,
          String? passwordHash,
          String? passwordSalt,
          String? fullName,
          Value<String?> email = const Value.absent(),
          Value<String?> phone = const Value.absent(),
          String? role,
          Value<Uint8List?> photo = const Value.absent(),
          bool? isActive,
          bool? isSystemAdmin,
          Value<String?> permissions = const Value.absent(),
          Value<DateTime?> lastLogin = const Value.absent(),
          DateTime? createdAt,
          DateTime? updatedAt}) =>
      User(
        id: id ?? this.id,
        uuid: uuid ?? this.uuid,
        username: username ?? this.username,
        passwordHash: passwordHash ?? this.passwordHash,
        passwordSalt: passwordSalt ?? this.passwordSalt,
        fullName: fullName ?? this.fullName,
        email: email.present ? email.value : this.email,
        phone: phone.present ? phone.value : this.phone,
        role: role ?? this.role,
        photo: photo.present ? photo.value : this.photo,
        isActive: isActive ?? this.isActive,
        isSystemAdmin: isSystemAdmin ?? this.isSystemAdmin,
        permissions: permissions.present ? permissions.value : this.permissions,
        lastLogin: lastLogin.present ? lastLogin.value : this.lastLogin,
        createdAt: createdAt ?? this.createdAt,
        updatedAt: updatedAt ?? this.updatedAt,
      );
  User copyWithCompanion(UsersCompanion data) {
    return User(
      id: data.id.present ? data.id.value : this.id,
      uuid: data.uuid.present ? data.uuid.value : this.uuid,
      username: data.username.present ? data.username.value : this.username,
      passwordHash: data.passwordHash.present
          ? data.passwordHash.value
          : this.passwordHash,
      passwordSalt: data.passwordSalt.present
          ? data.passwordSalt.value
          : this.passwordSalt,
      fullName: data.fullName.present ? data.fullName.value : this.fullName,
      email: data.email.present ? data.email.value : this.email,
      phone: data.phone.present ? data.phone.value : this.phone,
      role: data.role.present ? data.role.value : this.role,
      photo: data.photo.present ? data.photo.value : this.photo,
      isActive: data.isActive.present ? data.isActive.value : this.isActive,
      isSystemAdmin: data.isSystemAdmin.present
          ? data.isSystemAdmin.value
          : this.isSystemAdmin,
      permissions:
          data.permissions.present ? data.permissions.value : this.permissions,
      lastLogin: data.lastLogin.present ? data.lastLogin.value : this.lastLogin,
      createdAt: data.createdAt.present ? data.createdAt.value : this.createdAt,
      updatedAt: data.updatedAt.present ? data.updatedAt.value : this.updatedAt,
    );
  }

  @override
  String toString() {
    return (StringBuffer('User(')
          ..write('id: $id, ')
          ..write('uuid: $uuid, ')
          ..write('username: $username, ')
          ..write('passwordHash: $passwordHash, ')
          ..write('passwordSalt: $passwordSalt, ')
          ..write('fullName: $fullName, ')
          ..write('email: $email, ')
          ..write('phone: $phone, ')
          ..write('role: $role, ')
          ..write('photo: $photo, ')
          ..write('isActive: $isActive, ')
          ..write('isSystemAdmin: $isSystemAdmin, ')
          ..write('permissions: $permissions, ')
          ..write('lastLogin: $lastLogin, ')
          ..write('createdAt: $createdAt, ')
          ..write('updatedAt: $updatedAt')
          ..write(')'))
        .toString();
  }

  @override
  int get hashCode => Object.hash(
      id,
      uuid,
      username,
      passwordHash,
      passwordSalt,
      fullName,
      email,
      phone,
      role,
      $driftBlobEquality.hash(photo),
      isActive,
      isSystemAdmin,
      permissions,
      lastLogin,
      createdAt,
      updatedAt);
  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      (other is User &&
          other.id == this.id &&
          other.uuid == this.uuid &&
          other.username == this.username &&
          other.passwordHash == this.passwordHash &&
          other.passwordSalt == this.passwordSalt &&
          other.fullName == this.fullName &&
          other.email == this.email &&
          other.phone == this.phone &&
          other.role == this.role &&
          $driftBlobEquality.equals(other.photo, this.photo) &&
          other.isActive == this.isActive &&
          other.isSystemAdmin == this.isSystemAdmin &&
          other.permissions == this.permissions &&
          other.lastLogin == this.lastLogin &&
          other.createdAt == this.createdAt &&
          other.updatedAt == this.updatedAt);
}

