class ExamResult extends DataClass implements Insertable<ExamResult> {
  /// Primary key
  final int id;

  /// Exam foreign key
  final int examId;

  /// Student foreign key
  final int studentId;

  /// Total marks obtained
  final double totalMarksObtained;

  /// Total maximum marks
  final double totalMaxMarks;

  /// Percentage
  final double percentage;

  /// Overall grade
  final String overallGrade;

  /// GPA
  final double gpa;

  /// Rank in class
  final int? classRank;

  /// Pass/Fail status
  final bool isPassed;

  /// Teacher remarks
  final String? teacherRemarks;

  /// Principal remarks
  final String? principalRemarks;

  /// Record creation timestamp
  final DateTime createdAt;

  /// Record update timestamp
  final DateTime updatedAt;
  const ExamResult(
      {required this.id,
      required this.examId,
      required this.studentId,
      required this.totalMarksObtained,
      required this.totalMaxMarks,
      required this.percentage,
      required this.overallGrade,
      required this.gpa,
      this.classRank,
      required this.isPassed,
      this.teacherRemarks,
      this.principalRemarks,
      required this.createdAt,
      required this.updatedAt});
  @override
  Map<String, Expression> toColumns(bool nullToAbsent) {
    final map = <String, Expression>{};
    map['id'] = Variable<int>(id);
    map['exam_id'] = Variable<int>(examId);
    map['student_id'] = Variable<int>(studentId);
    map['total_marks_obtained'] = Variable<double>(totalMarksObtained);
    map['total_max_marks'] = Variable<double>(totalMaxMarks);
    map['percentage'] = Variable<double>(percentage);
    map['overall_grade'] = Variable<String>(overallGrade);
    map['gpa'] = Variable<double>(gpa);
    if (!nullToAbsent || classRank != null) {
      map['class_rank'] = Variable<int>(classRank);
    }
    map['is_passed'] = Variable<bool>(isPassed);
    if (!nullToAbsent || teacherRemarks != null) {
      map['teacher_remarks'] = Variable<String>(teacherRemarks);
    }
    if (!nullToAbsent || principalRemarks != null) {
      map['principal_remarks'] = Variable<String>(principalRemarks);
    }
    map['created_at'] = Variable<DateTime>(createdAt);
    map['updated_at'] = Variable<DateTime>(updatedAt);
    return map;
  }

  ExamResultsCompanion toCompanion(bool nullToAbsent) {
    return ExamResultsCompanion(
      id: Value(id),
      examId: Value(examId),
      studentId: Value(studentId),
      totalMarksObtained: Value(totalMarksObtained),
      totalMaxMarks: Value(totalMaxMarks),
      percentage: Value(percentage),
      overallGrade: Value(overallGrade),
      gpa: Value(gpa),
      classRank: classRank == null && nullToAbsent
          ? const Value.absent()
          : Value(classRank),
      isPassed: Value(isPassed),
      teacherRemarks: teacherRemarks == null && nullToAbsent
          ? const Value.absent()
          : Value(teacherRemarks),
      principalRemarks: principalRemarks == null && nullToAbsent
          ? const Value.absent()
          : Value(principalRemarks),
      createdAt: Value(createdAt),
      updatedAt: Value(updatedAt),
    );
  }

  factory ExamResult.fromJson(Map<String, dynamic> json,
      {ValueSerializer? serializer}) {
    serializer ??= driftRuntimeOptions.defaultSerializer;
    return ExamResult(
      id: serializer.fromJson<int>(json['id']),
      examId: serializer.fromJson<int>(json['examId']),
      studentId: serializer.fromJson<int>(json['studentId']),
      totalMarksObtained:
          serializer.fromJson<double>(json['totalMarksObtained']),
      totalMaxMarks: serializer.fromJson<double>(json['totalMaxMarks']),
      percentage: serializer.fromJson<double>(json['percentage']),
      overallGrade: serializer.fromJson<String>(json['overallGrade']),
      gpa: serializer.fromJson<double>(json['gpa']),
      classRank: serializer.fromJson<int?>(json['classRank']),
      isPassed: serializer.fromJson<bool>(json['isPassed']),
      teacherRemarks: serializer.fromJson<String?>(json['teacherRemarks']),
      principalRemarks: serializer.fromJson<String?>(json['principalRemarks']),
      createdAt: serializer.fromJson<DateTime>(json['createdAt']),
      updatedAt: serializer.fromJson<DateTime>(json['updatedAt']),
    );
  }
  @override
