class Invoice extends DataClass implements Insertable<Invoice> {
  /// Primary key
  final int id;

  /// Unique invoice number
  final String invoiceNumber;

  /// Student foreign key
  final int studentId;

  /// Invoice month (YYYY-MM format)
  final String month;

  /// Academic year
  final String academicYear;

  /// Total amount (sum of all fee items)
  final double totalAmount;

  /// Discount amount (from concessions)
  final double discountAmount;

  /// Net amount (total - discount)
  final double netAmount;

  /// Amount paid so far
  final double paidAmount;

  /// Balance amount (net - paid)
  final double balanceAmount;

  /// Invoice status (pending, partial, paid, overdue)
  final String status;

  /// Issue date
  final DateTime issueDate;

  /// Due date
  final DateTime dueDate;

  /// Last payment date
  final DateTime? lastPaymentDate;

  /// Notes
  final String? notes;

  /// Generated by (user ID)
  final int generatedBy;

  /// Record creation timestamp
  final DateTime createdAt;

  /// Record update timestamp
  final DateTime updatedAt;
  const Invoice(
      {required this.id,
      required this.invoiceNumber,
      required this.studentId,
      required this.month,
      required this.academicYear,
      required this.totalAmount,
      required this.discountAmount,
      required this.netAmount,
      required this.paidAmount,
      required this.balanceAmount,
      required this.status,
      required this.issueDate,
      required this.dueDate,
      this.lastPaymentDate,
      this.notes,
      required this.generatedBy,
      required this.createdAt,
      required this.updatedAt});
  @override
  Map<String, Expression> toColumns(bool nullToAbsent) {
    final map = <String, Expression>{};
    map['id'] = Variable<int>(id);
    map['invoice_number'] = Variable<String>(invoiceNumber);
    map['student_id'] = Variable<int>(studentId);
    map['month'] = Variable<String>(month);
    map['academic_year'] = Variable<String>(academicYear);
    map['total_amount'] = Variable<double>(totalAmount);
    map['discount_amount'] = Variable<double>(discountAmount);
    map['net_amount'] = Variable<double>(netAmount);
    map['paid_amount'] = Variable<double>(paidAmount);
    map['balance_amount'] = Variable<double>(balanceAmount);
    map['status'] = Variable<String>(status);
    map['issue_date'] = Variable<DateTime>(issueDate);
    map['due_date'] = Variable<DateTime>(dueDate);
    if (!nullToAbsent || lastPaymentDate != null) {
      map['last_payment_date'] = Variable<DateTime>(lastPaymentDate);
    }
    if (!nullToAbsent || notes != null) {
      map['notes'] = Variable<String>(notes);
    }
    map['generated_by'] = Variable<int>(generatedBy);
    map['created_at'] = Variable<DateTime>(createdAt);
    map['updated_at'] = Variable<DateTime>(updatedAt);
    return map;
  }

  InvoicesCompanion toCompanion(bool nullToAbsent) {
    return InvoicesCompanion(
      id: Value(id),
      invoiceNumber: Value(invoiceNumber),
      studentId: Value(studentId),
      month: Value(month),
      academicYear: Value(academicYear),
      totalAmount: Value(totalAmount),
      discountAmount: Value(discountAmount),
      netAmount: Value(netAmount),
      paidAmount: Value(paidAmount),
      balanceAmount: Value(balanceAmount),
      status: Value(status),
      issueDate: Value(issueDate),
      dueDate: Value(dueDate),
      lastPaymentDate: lastPaymentDate == null && nullToAbsent
          ? const Value.absent()
          : Value(lastPaymentDate),
      notes:
          notes == null && nullToAbsent ? const Value.absent() : Value(notes),
      generatedBy: Value(generatedBy),
      createdAt: Value(createdAt),
      updatedAt: Value(updatedAt),
    );
  }

  factory Invoice.fromJson(Map<String, dynamic> json,
      {ValueSerializer? serializer}) {
    serializer ??= driftRuntimeOptions.defaultSerializer;
    return Invoice(
      id: serializer.fromJson<int>(json['id']),
      invoiceNumber: serializer.fromJson<String>(json['invoiceNumber']),
      studentId: serializer.fromJson<int>(json['studentId']),
      month: serializer.fromJson<String>(json['month']),
      academicYear: serializer.fromJson<String>(json['academicYear']),
      totalAmount: serializer.fromJson<double>(json['totalAmount']),
      discountAmount: serializer.fromJson<double>(json['discountAmount']),
      netAmount: serializer.fromJson<double>(json['netAmount']),
      paidAmount: serializer.fromJson<double>(json['paidAmount']),
      balanceAmount: serializer.fromJson<double>(json['balanceAmount']),
      status: serializer.fromJson<String>(json['status']),
      issueDate: serializer.fromJson<DateTime>(json['issueDate']),
      dueDate: serializer.fromJson<DateTime>(json['dueDate']),
      lastPaymentDate: serializer.fromJson<DateTime?>(json['lastPaymentDate']),
      notes: serializer.fromJson<String?>(json['notes']),
      generatedBy: serializer.fromJson<int>(json['generatedBy']),
      createdAt: serializer.fromJson<DateTime>(json['createdAt']),
      updatedAt: serializer.fromJson<DateTime>(json['updatedAt']),
    );
  }
  @override
  Map<String, dynamic> toJson({ValueSerializer? serializer}) {
    serializer ??= driftRuntimeOptions.defaultSerializer;
    return <String, dynamic>{
      'id': serializer.toJson<int>(id),
      'invoiceNumber': serializer.toJson<String>(invoiceNumber),
      'studentId': serializer.toJson<int>(studentId),
      'month': serializer.toJson<String>(month),
      'academicYear': serializer.toJson<String>(academicYear),
      'totalAmount': serializer.toJson<double>(totalAmount),
      'discountAmount': serializer.toJson<double>(discountAmount),
      'netAmount': serializer.toJson<double>(netAmount),
      'paidAmount': serializer.toJson<double>(paidAmount),
      'balanceAmount': serializer.toJson<double>(balanceAmount),
      'status': serializer.toJson<String>(status),
      'issueDate': serializer.toJson<DateTime>(issueDate),
      'dueDate': serializer.toJson<DateTime>(dueDate),
      'lastPaymentDate': serializer.toJson<DateTime?>(lastPaymentDate),
      'notes': serializer.toJson<String?>(notes),
      'generatedBy': serializer.toJson<int>(generatedBy),
      'createdAt': serializer.toJson<DateTime>(createdAt),
      'updatedAt': serializer.toJson<DateTime>(updatedAt),
    };
  }

  Invoice copyWith(
          {int? id,
          String? invoiceNumber,
          int? studentId,
          String? month,
          String? academicYear,
          double? totalAmount,
          double? discountAmount,
          double? netAmount,
          double? paidAmount,
          double? balanceAmount,
          String? status,
          DateTime? issueDate,
          DateTime? dueDate,
          Value<DateTime?> lastPaymentDate = const Value.absent(),
          Value<String?> notes = const Value.absent(),
          int? generatedBy,
          DateTime? createdAt,
          DateTime? updatedAt}) =>
      Invoice(
        id: id ?? this.id,
        invoiceNumber: invoiceNumber ?? this.invoiceNumber,
        studentId: studentId ?? this.studentId,
        month: month ?? this.month,
        academicYear: academicYear ?? this.academicYear,
        totalAmount: totalAmount ?? this.totalAmount,
        discountAmount: discountAmount ?? this.discountAmount,
        netAmount: netAmount ?? this.netAmount,
        paidAmount: paidAmount ?? this.paidAmount,
        balanceAmount: balanceAmount ?? this.balanceAmount,
        status: status ?? this.status,
        issueDate: issueDate ?? this.issueDate,
        dueDate: dueDate ?? this.dueDate,
        lastPaymentDate: lastPaymentDate.present
            ? lastPaymentDate.value
            : this.lastPaymentDate,
        notes: notes.present ? notes.value : this.notes,
        generatedBy: generatedBy ?? this.generatedBy,
        createdAt: createdAt ?? this.createdAt,
        updatedAt: updatedAt ?? this.updatedAt,
      );
  Invoice copyWithCompanion(InvoicesCompanion data) {
    return Invoice(
      id: data.id.present ? data.id.value : this.id,
      invoiceNumber: data.invoiceNumber.present
          ? data.invoiceNumber.value
          : this.invoiceNumber,
      studentId: data.studentId.present ? data.studentId.value : this.studentId,
      month: data.month.present ? data.month.value : this.month,
      academicYear: data.academicYear.present
          ? data.academicYear.value
          : this.academicYear,
      totalAmount:
          data.totalAmount.present ? data.totalAmount.value : this.totalAmount,
      discountAmount: data.discountAmount.present
          ? data.discountAmount.value
          : this.discountAmount,
      netAmount: data.netAmount.present ? data.netAmount.value : this.netAmount,
      paidAmount:
          data.paidAmount.present ? data.paidAmount.value : this.paidAmount,
      balanceAmount: data.balanceAmount.present
          ? data.balanceAmount.value
          : this.balanceAmount,
      status: data.status.present ? data.status.value : this.status,
      issueDate: data.issueDate.present ? data.issueDate.value : this.issueDate,
      dueDate: data.dueDate.present ? data.dueDate.value : this.dueDate,
      lastPaymentDate: data.lastPaymentDate.present
          ? data.lastPaymentDate.value
          : this.lastPaymentDate,
      notes: data.notes.present ? data.notes.value : this.notes,
      generatedBy:
          data.generatedBy.present ? data.generatedBy.value : this.generatedBy,
      createdAt: data.createdAt.present ? data.createdAt.value : this.createdAt,
      updatedAt: data.updatedAt.present ? data.updatedAt.value : this.updatedAt,
    );
  }

  @override
  String toString() {
    return (StringBuffer('Invoice(')
          ..write('id: $id, ')
          ..write('invoiceNumber: $invoiceNumber, ')
          ..write('studentId: $studentId, ')
          ..write('month: $month, ')
          ..write('academicYear: $academicYear, ')
          ..write('totalAmount: $totalAmount, ')
          ..write('discountAmount: $discountAmount, ')
          ..write('netAmount: $netAmount, ')
          ..write('paidAmount: $paidAmount, ')
          ..write('balanceAmount: $balanceAmount, ')
          ..write('status: $status, ')
          ..write('issueDate: $issueDate, ')
          ..write('dueDate: $dueDate, ')
          ..write('lastPaymentDate: $lastPaymentDate, ')
          ..write('notes: $notes, ')
          ..write('generatedBy: $generatedBy, ')
          ..write('createdAt: $createdAt, ')
          ..write('updatedAt: $updatedAt')
          ..write(')'))
        .toString();
  }

  @override
  int get hashCode => Object.hash(
      id,
      invoiceNumber,
      studentId,
      month,
      academicYear,
      totalAmount,
      discountAmount,
      netAmount,
      paidAmount,
      balanceAmount,
      status,
      issueDate,
      dueDate,
      lastPaymentDate,
      notes,
      generatedBy,
      createdAt,
      updatedAt);
  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      (other is Invoice &&
          other.id == this.id &&
          other.invoiceNumber == this.invoiceNumber &&
          other.studentId == this.studentId &&
          other.month == this.month &&
          other.academicYear == this.academicYear &&
          other.totalAmount == this.totalAmount &&
          other.discountAmount == this.discountAmount &&
          other.netAmount == this.netAmount &&
          other.paidAmount == this.paidAmount &&
