class Concession extends DataClass implements Insertable<Concession> {
  /// Primary key
  final int id;

  /// Student foreign key
  final int studentId;

  /// Fee type foreign key (null means applies to all fees)
  final int? feeTypeId;

  /// Discount type (percentage, fixed)
  final String discountType;

  /// Discount value (percentage or fixed amount)
  final double discountValue;

  /// Reason for concession
  final String? reason;

  /// Start date (from when concession applies)
  final DateTime startDate;

  /// End date (null if ongoing)
  final DateTime? endDate;

  /// Is concession currently active
  final bool isActive;

  /// Approved by (user ID)
  final int approvedBy;

  /// Record creation timestamp
  final DateTime createdAt;

  /// Record update timestamp
  final DateTime updatedAt;
  const Concession(
      {required this.id,
      required this.studentId,
      this.feeTypeId,
      required this.discountType,
      required this.discountValue,
      this.reason,
      required this.startDate,
      this.endDate,
      required this.isActive,
      required this.approvedBy,
      required this.createdAt,
      required this.updatedAt});
