  Map<String, Expression> toColumns(bool nullToAbsent) {
    final map = <String, Expression>{};
    map['id'] = Variable<int>(id);
    map['student_id'] = Variable<int>(studentId);
    if (!nullToAbsent || feeTypeId != null) {
      map['fee_type_id'] = Variable<int>(feeTypeId);
    }
    map['discount_type'] = Variable<String>(discountType);
    map['discount_value'] = Variable<double>(discountValue);
    if (!nullToAbsent || reason != null) {
      map['reason'] = Variable<String>(reason);
    }
    map['start_date'] = Variable<DateTime>(startDate);
    if (!nullToAbsent || endDate != null) {
      map['end_date'] = Variable<DateTime>(endDate);
    }
    map['is_active'] = Variable<bool>(isActive);
    map['approved_by'] = Variable<int>(approvedBy);
    map['created_at'] = Variable<DateTime>(createdAt);
    map['updated_at'] = Variable<DateTime>(updatedAt);
    return map;
  }

  ConcessionsCompanion toCompanion(bool nullToAbsent) {
    return ConcessionsCompanion(
      id: Value(id),
      studentId: Value(studentId),
      feeTypeId: feeTypeId == null && nullToAbsent
          ? const Value.absent()
          : Value(feeTypeId),
      discountType: Value(discountType),
      discountValue: Value(discountValue),
      reason:
          reason == null && nullToAbsent ? const Value.absent() : Value(reason),
      startDate: Value(startDate),
      endDate: endDate == null && nullToAbsent
