class LeaveType extends DataClass implements Insertable<LeaveType> {
  /// Primary key
  final int id;

  /// Leave type name (e.g., "Sick Leave", "Casual Leave")
  final String name;

  /// Description
  final String? description;

  /// Maximum days allowed per year
  final int maxDays;

  /// Is paid leave
  final bool isPaid;

  /// Can be carried forward to next year
  final bool canCarryForward;

  /// Maximum days that can be carried forward
  final int maxCarryForwardDays;

  /// Is active
  final bool isActive;

  /// Record creation timestamp
  final DateTime createdAt;
  const LeaveType(
      {required this.id,
      required this.name,
      this.description,
      required this.maxDays,
      required this.isPaid,
      required this.canCarryForward,
      required this.maxCarryForwardDays,
      required this.isActive,
      required this.createdAt});
