  Map<String, Expression> toColumns(bool nullToAbsent) {
    final map = <String, Expression>{};
    map['id'] = Variable<int>(id);
    map['name'] = Variable<String>(name);
    if (!nullToAbsent || description != null) {
      map['description'] = Variable<String>(description);
    }
    map['max_days'] = Variable<int>(maxDays);
    map['is_paid'] = Variable<bool>(isPaid);
    map['can_carry_forward'] = Variable<bool>(canCarryForward);
    map['max_carry_forward_days'] = Variable<int>(maxCarryForwardDays);
    map['is_active'] = Variable<bool>(isActive);
    map['created_at'] = Variable<DateTime>(createdAt);
    return map;
  }

  LeaveTypesCompanion toCompanion(bool nullToAbsent) {
    return LeaveTypesCompanion(
      id: Value(id),
      name: Value(name),
      description: description == null && nullToAbsent
          ? const Value.absent()
          : Value(description),
