    if (subjectId.present) {
      map['subject_id'] = Variable<int>(subjectId.value);
    }
    if (academicYear.present) {
      map['academic_year'] = Variable<String>(academicYear.value);
    }
    if (isClassTeacher.present) {
      map['is_class_teacher'] = Variable<bool>(isClassTeacher.value);
    }
    if (createdAt.present) {
      map['created_at'] = Variable<DateTime>(createdAt.value);
    }
    return map;
  }

  @override
  String toString() {
    return (StringBuffer('StaffSubjectAssignmentsCompanion(')
          ..write('id: $id, ')
          ..write('staffId: $staffId, ')
          ..write('classId: $classId, ')
          ..write('sectionId: $sectionId, ')
          ..write('subjectId: $subjectId, ')
          ..write('academicYear: $academicYear, ')
          ..write('isClassTeacher: $isClassTeacher, ')
          ..write('createdAt: $createdAt')
          ..write(')'))
        .toString();
  }
}

