class PayrollData extends DataClass implements Insertable<PayrollData> {
  /// Primary key
  final int id;

  /// Staff foreign key
  final int staffId;

  /// Payroll month (YYYY-MM format)
  final String month;

  /// Basic salary for this month
  final double basicSalary;

  /// Total allowances
  final double allowances;

  /// Allowances breakdown (JSON)
  final String? allowancesBreakdown;

  /// Total deductions
  final double deductions;

  /// Deductions breakdown (JSON)
  final String? deductionsBreakdown;

  /// Net salary (basic + allowances - deductions)
  final double netSalary;

  /// Working days in month
  final int workingDays;

  /// Days present
  final int daysPresent;

  /// Days absent
  final int daysAbsent;

  /// Leave days (paid)
  final int leaveDays;

  /// Payment status (pending, paid)
  final String status;

  /// Payment date
  final DateTime? paidDate;

  /// Payment mode (cash, bank_transfer, cheque)
  final String? paymentMode;

  /// Reference number
  final String? referenceNumber;

  /// Remarks
  final String? remarks;

  /// Processed by (user ID)
  final int? processedBy;

  /// Record creation timestamp
  final DateTime createdAt;

  /// Record update timestamp
  final DateTime updatedAt;
  const PayrollData(
      {required this.id,
      required this.staffId,
      required this.month,
      required this.basicSalary,
      required this.allowances,
      this.allowancesBreakdown,
      required this.deductions,
      this.deductionsBreakdown,
