    map['operator_name'] = Variable<String>(operatorName);
    if (!nullToAbsent || operatorPhone != null) {
      map['operator_phone'] = Variable<String>(operatorPhone);
    }
    map['business_model'] = Variable<String>(businessModel);
    map['monthly_rent'] = Variable<double>(monthlyRent);
    map['total_investment'] = Variable<double>(totalInvestment);
    map['is_active'] = Variable<bool>(isActive);
    map['created_at'] = Variable<DateTime>(createdAt);
    map['updated_at'] = Variable<DateTime>(updatedAt);
    return map;
  }

  CanteensCompanion toCompanion(bool nullToAbsent) {
    return CanteensCompanion(
      id: Value(id),
      name: Value(name),
      operatorName: Value(operatorName),
      operatorPhone: operatorPhone == null && nullToAbsent
          ? const Value.absent()
          : Value(operatorPhone),
      businessModel: Value(businessModel),
      monthlyRent: Value(monthlyRent),
      totalInvestment: Value(totalInvestment),
      isActive: Value(isActive),
      createdAt: Value(createdAt),
      updatedAt: Value(updatedAt),
