class SyncLog extends DataClass implements Insertable<SyncLog> {
  /// Primary key
  final int id;

  /// Device UUID reference
  final String deviceId;

  /// Teacher/staff foreign key
  final int teacherId;

  /// Sync type: 'upload', 'download', 'full'
  final String syncType;

  /// Number of records processed
  final int recordsCount;

  /// Status: 'success', 'partial', 'failed'
  final String status;

  /// Error message if failed
  final String? errorMessage;

  /// Record creation timestamp
  final DateTime createdAt;
  const SyncLog(
      {required this.id,
      required this.deviceId,
      required this.teacherId,
      required this.syncType,
      required this.recordsCount,
      required this.status,
      this.errorMessage,
      required this.createdAt});
  @override
  Map<String, Expression> toColumns(bool nullToAbsent) {
    final map = <String, Expression>{};
    map['id'] = Variable<int>(id);
    map['device_id'] = Variable<String>(deviceId);
    map['teacher_id'] = Variable<int>(teacherId);
    map['sync_type'] = Variable<String>(syncType);
    map['records_count'] = Variable<int>(recordsCount);
    map['status'] = Variable<String>(status);
    if (!nullToAbsent || errorMessage != null) {
      map['error_message'] = Variable<String>(errorMessage);
    }
    map['created_at'] = Variable<DateTime>(createdAt);
    return map;
  }

  SyncLogsCompanion toCompanion(bool nullToAbsent) {
    return SyncLogsCompanion(
      id: Value(id),
      deviceId: Value(deviceId),
      teacherId: Value(teacherId),
      syncType: Value(syncType),
      recordsCount: Value(recordsCount),
      status: Value(status),
      errorMessage: errorMessage == null && nullToAbsent
          ? const Value.absent()
          : Value(errorMessage),
      createdAt: Value(createdAt),
    );
  }

  factory SyncLog.fromJson(Map<String, dynamic> json,
      {ValueSerializer? serializer}) {
    serializer ??= driftRuntimeOptions.defaultSerializer;
    return SyncLog(
      id: serializer.fromJson<int>(json['id']),
      deviceId: serializer.fromJson<String>(json['deviceId']),
      teacherId: serializer.fromJson<int>(json['teacherId']),
      syncType: serializer.fromJson<String>(json['syncType']),
      recordsCount: serializer.fromJson<int>(json['recordsCount']),
      status: serializer.fromJson<String>(json['status']),
      errorMessage: serializer.fromJson<String?>(json['errorMessage']),
      createdAt: serializer.fromJson<DateTime>(json['createdAt']),
    );
  }
  @override
  Map<String, dynamic> toJson({ValueSerializer? serializer}) {
    serializer ??= driftRuntimeOptions.defaultSerializer;
    return <String, dynamic>{
      'id': serializer.toJson<int>(id),
      'deviceId': serializer.toJson<String>(deviceId),
      'teacherId': serializer.toJson<int>(teacherId),
      'syncType': serializer.toJson<String>(syncType),
      'recordsCount': serializer.toJson<int>(recordsCount),
      'status': serializer.toJson<String>(status),
      'errorMessage': serializer.toJson<String?>(errorMessage),
      'createdAt': serializer.toJson<DateTime>(createdAt),
    };
  }

  SyncLog copyWith(
          {int? id,
          String? deviceId,
          int? teacherId,
          String? syncType,
          int? recordsCount,
          String? status,
          Value<String?> errorMessage = const Value.absent(),
          DateTime? createdAt}) =>
      SyncLog(
        id: id ?? this.id,
        deviceId: deviceId ?? this.deviceId,
        teacherId: teacherId ?? this.teacherId,
        syncType: syncType ?? this.syncType,
        recordsCount: recordsCount ?? this.recordsCount,
        status: status ?? this.status,
        errorMessage:
            errorMessage.present ? errorMessage.value : this.errorMessage,
        createdAt: createdAt ?? this.createdAt,
      );
  SyncLog copyWithCompanion(SyncLogsCompanion data) {
    return SyncLog(
      id: data.id.present ? data.id.value : this.id,
      deviceId: data.deviceId.present ? data.deviceId.value : this.deviceId,
      teacherId: data.teacherId.present ? data.teacherId.value : this.teacherId,
      syncType: data.syncType.present ? data.syncType.value : this.syncType,
      recordsCount: data.recordsCount.present
          ? data.recordsCount.value
          : this.recordsCount,
      status: data.status.present ? data.status.value : this.status,
      errorMessage: data.errorMessage.present
          ? data.errorMessage.value
          : this.errorMessage,
      createdAt: data.createdAt.present ? data.createdAt.value : this.createdAt,
    );
  }

  @override
  String toString() {
    return (StringBuffer('SyncLog(')
          ..write('id: $id, ')
          ..write('deviceId: $deviceId, ')
          ..write('teacherId: $teacherId, ')
          ..write('syncType: $syncType, ')
          ..write('recordsCount: $recordsCount, ')
          ..write('status: $status, ')
          ..write('errorMessage: $errorMessage, ')
          ..write('createdAt: $createdAt')
          ..write(')'))
        .toString();
  }

  @override
  int get hashCode => Object.hash(id, deviceId, teacherId, syncType,
      recordsCount, status, errorMessage, createdAt);
  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      (other is SyncLog &&
          other.id == this.id &&
          other.deviceId == this.deviceId &&
          other.teacherId == this.teacherId &&
          other.syncType == this.syncType &&
          other.recordsCount == this.recordsCount &&
          other.status == this.status &&
          other.errorMessage == this.errorMessage &&
          other.createdAt == this.createdAt);
}

